const body = $json.body || $json;
return {
  external_call_id: body.external_call_id,
  ordem_servico_id: body.ordem_servico_id,
  cliente_nome: body.cliente?.nome,
  cliente_telefone: body.cliente?.telefone ? body.cliente.telefone.replace(/^\+55/, '').replace(/^\+/, '') : '',
  item_reparado: body.item_reparado,
  valor_orcamento: body.valor_orcamento,
  valor_pago: body.valor_pago,
  valor_restante: (body.valor_orcamento - body.valor_pago).toFixed(2),
  defeito_relatado: body.defeito_relatado,
  callback_url: body.callback_url
};
